<!--
  App.vue - 应用根组件

  uni-app 的根组件仅用于注入全局样式，不包含业务逻辑。
  全局 SCSS 样式通过 @use 引入（含基础重置、中医主题色、字体等）。
-->
<template></template>

<script>
import { useAppStore } from '@/stores/app.js'

export default {
  onLaunch() {
    // #ifdef MP-WEIXIN
    // 微信小程序：动态加载楷体字体
    uni.loadFontFace({
      global: true,
      family: 'KaitiGB2312',
      source: 'url("data:font/ttf;charset=utf-8;base64,")',
      success() {
        console.log('KaitiGB2312 font loaded')
      },
      fail(err) {
        console.warn('KaitiGB2312 font load failed:', err)
      }
    })
    // #endif
    // #ifndef MP-WEIXIN
    // App端 / H5：@font-face 在 styles/index.scss 中已配置（APP-PLUS）
    // #endif

    // #ifdef APP-PLUS
    const store = useAppStore()
    store.syncSystemThemeFromDevice()
    try {
      uni.onThemeChange((res) => {
        store.syncSystemTheme(res.theme)
      })
    } catch {
      // 部分运行环境不支持主题变化监听，onShow 时会再同步一次。
    }
    // #endif
  },
  onShow() {
    // #ifdef APP-PLUS
    useAppStore().syncSystemThemeFromDevice()
    // #endif
  },
  onHide() {}
}
</script>

<style lang="scss">
@use '@/styles/index.scss';
</style>
